import { FormDialog } from "@/components/common/dialogs/FormDialog";
import { memo, useEffect } from "react";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { SubmitHandler, useForm } from "react-hook-form";
import { Input } from "@/components/ui/input";
import { zodResolver } from "@hookform/resolvers/zod";
import { CreateJobPayload } from "../types/jobs.types";
import { createJobSchema } from "../schemas/create-job.schema";
import { useJobActions } from "../hooks/useJobsActions";
import { useCountries } from "@/shared/hooks/useCountries";
import { DynamicSelect } from "@/components/common/DynamicSelect";
import { Switch } from "@/components/ui/switch";
import type { UseFormReturn } from "react-hook-form";
import { CountrySelect } from "./create-form/CountrySelect";
import { EmploymentTypeSelect } from "./create-form/EmploymentTypeSelect";
import { ExperienceLevelSelect } from "./create-form/ExperienceLevelSelect";
import { StatusSelect } from "./create-form/StatusSelect";
import { Editor } from "@/components/blocks/editor-00/editor";

const createJobResolver = zodResolver(createJobSchema);

interface CreateJobFormDialogProps {
  onSuccess: () => void;
  open: boolean;
  setOpen: (open: boolean) => void;
}

export function CreateJobFormDialog({
  onSuccess,
  open = false,
  setOpen,
}: CreateJobFormDialogProps) {
  const { create, loading, apiError, clearApiError } = useJobActions();
  const { countries, loading: countriesLoading } = useCountries();

  const form = useForm<CreateJobPayload>({
    resolver: createJobResolver,
    defaultValues: {
      country: "",
      city: "",
      title: "",
      department: "",
      employmentType: undefined,
      experienceLevel: undefined,
      salaryMin: undefined,
      salaryMax: undefined,
      isRemote: false,
      status: undefined,
      description: "",
    },
  });

  const handleSubmit: SubmitHandler<CreateJobPayload> = async (values) => {
    clearApiError();
    try {
      await create(values);
      form.reset();
      onSuccess();
    } catch {
      //=== errors handled via useJobActions/useApiError
    }
  };

  const handleClose = () => {
    form.reset();
    clearApiError();
    setOpen(false);
  };

  useEffect(() => {
    if (apiError?.validationErrors) {
      apiError.validationErrors.forEach((error) => {
        form.setError(error.field as keyof CreateJobPayload, {
          type: "server",
          message: error.errors[0],
        });
      });
    } else {
      form.clearErrors();
    }
  }, [apiError?.validationErrors, form]);

  return (
    <FormDialog
      title="Create Job"
      isOpen={open}
      onClose={handleClose}
      onSubmit={handleSubmit}
      loading={loading}
      formId="createJobForm"
      className="sm:max-w-3xl"
      forceMount
    >
      <JobFormContent
        form={form}
        onSubmit={handleSubmit}
      />
    </FormDialog>
  );
}

interface JobFormContentProps {
  form: UseFormReturn<CreateJobPayload>;
  onSubmit: SubmitHandler<CreateJobPayload>;
}

const JobFormContent = memo(function JobFormContent({
  form,
  onSubmit,
}: JobFormContentProps) {
  return (
    <Form {...form}>
      <form
        id="createJobForm"
        onSubmit={form.handleSubmit(onSubmit)}
        className="space-y-6 mt-3 mb-2"
      >
        <div className="space-y-5">
          {/* ==== TITLE & DEPARTMENT === */}
          <div className="grid sm:grid-cols-2 gap-4">
            <FormField
              control={form.control}
              name="title"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Title</FormLabel>
                  <FormControl>
                    <Input placeholder="e.g. Marketing" {...field} />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />

            <FormField
              control={form.control}
              name="department"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Department</FormLabel>
                  <FormControl>
                    <DynamicSelect
                      placeholder="Select department"
                      endpoint={`${process.env.NEXT_PUBLIC_API_VERSION ?? "V1"}/jobs/departments`}
                      label="title"
                      value="_id"
                      field={field}
                    />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />
          </div>

          {/* ==== COUNTRY & CITY === */}
          <div className="grid sm:grid-cols-2 gap-4">
            <CountrySelect
              control={form.control}
            />

            <FormField
              control={form.control}
              name="city"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>City</FormLabel>
                  <FormControl>
                    <Input placeholder="e.g. Marketing" {...field} />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />
          </div>

          {/* ==== EMPLOYMENT TYPE & EXPERIENCE LEVEL === */}
          <div className="grid sm:grid-cols-2 gap-4">
            <EmploymentTypeSelect 
             control={form.control}
            />

            <ExperienceLevelSelect
             control={form.control}
            />
          </div>

          {/* ==== SALARY MIN & MAX === */}
          <div className="grid sm:grid-cols-2 gap-4 items-center">
            <FormField
              control={form.control}
              name="salaryMax"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Salary Max</FormLabel>
                  <FormControl>
                    <Input
                      type="number"
                      placeholder="e.g. 60000"
                      min={0}
                      {...field}
                    />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />

            <FormField
              control={form.control}
              name="salaryMin"
              render={({ field }) => (
                <FormItem>
                  <FormLabel className="mb-0">Salary Min</FormLabel>
                  <FormControl>
                    <Input
                      type="number"
                      placeholder="e.g. 40000"
                      min={0}
                      {...field}
                    />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />
          </div>

          {/* ==== STATUS & REMOTE === */}
          <div className="grid sm:grid-cols-2 gap-4 items-center">
            <StatusSelect 
              control={form.control}
            />

            <FormField
              control={form.control}
              name="isRemote"
              render={({ field }) => (
                <FormItem>
                  <FormLabel className="mb-0">Remote</FormLabel>
                  <FormControl>
                    <Switch
                      id="remote-job"
                      checked={field.value ?? false}
                      onCheckedChange={field.onChange}
                    />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />
          </div>

          {/* ==== DESCRIPTION === */}
           <FormField
              control={form.control}
              name="isRemote"
              render={({ field }) => (
                <FormItem>
                  <FormLabel className="mb-0">Remote</FormLabel>
                  <FormControl>
                    <Editor
                      value={field.value}
                      onChange={field.onChange}
                    />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />
        </div>
      </form>
    </Form>
  );
});
